fn volvox_grid_service_run_stream(ctx: &mut VolvoxGridServiceStreamContext) {
    if ctx.closed || ctx.finished {
        return;
    }

    let plugin = match get_volvox_grid_service_plugin() {
        Some(p) => p,
        None => {
            set_last_error("plugin not registered".into());
            ctx.stream_error = true;
            ctx.finished = true;
            return;
        }
    };

    match ctx.method {
        VolvoxGridServiceStreamMethod::RenderSession => {
            if ctx.started || !ctx.send_closed {
                return;
            }

            let bidi = LocalStreamBidi::<RenderInput, RenderOutput>::from_queue(std::mem::take(
                &mut ctx.send_queue,
            ));
            match plugin.render_session(&bidi) {
                Ok(_) => {
                    if let Some(e) = bidi.take_decode_error() {
                        set_last_error(e);
                        ctx.stream_error = true;
                    } else if let Some(e) = bidi.take_encode_error() {
                        set_last_error(e);
                        ctx.stream_error = true;
                    } else {
                        for out in bidi.take_outputs() {
                            ctx.recv_queue.push_back(out);
                        }
                        clear_last_error();
                    }
                }
                Err(e) => {
                    set_last_error(e);
                    ctx.stream_error = true;
                }
            }

            ctx.finished = true;
            ctx.started = true;
        }
        VolvoxGridServiceStreamMethod::EventStream => {
            if ctx.started {
                return;
            }

            let data = match ctx.send_queue.pop_front() {
                Some(d) => d,
                None => return,
            };

            if !ctx.send_queue.is_empty() {
                set_last_error("server stream expects one request".into());
                ctx.stream_error = true;
                ctx.finished = true;
                ctx.started = true;
                return;
            }

            let req = match GridHandle::decode(data.as_slice()) {
                Ok(r) => r,
                Err(e) => {
                    set_last_error(format!("decode stream request: {}", e));
                    ctx.stream_error = true;
                    ctx.finished = true;
                    ctx.started = true;
                    return;
                }
            };

            let sender = LocalStreamSender::<GridEvent>::new();
            match plugin.event_stream(req, &sender) {
                Ok(_) => {
                    if let Some(e) = sender.take_encode_error() {
                        set_last_error(e);
                        ctx.stream_error = true;
                    } else {
                        for out in sender.take_outputs() {
                            ctx.recv_queue.push_back(out);
                        }
                        clear_last_error();
                    }
                }
                Err(e) => {
                    set_last_error(e);
                    ctx.stream_error = true;
                }
            }

            ctx.finished = true;
            ctx.started = true;
        }
    }
}

