#[wasm_bindgen]
pub fn volvox_grid_load_demo(grid_id: i64, demo: &str) -> Vec<u8> {
    let plugin = match get_volvox_grid_service_plugin() {
        Some(p) => p,
        None => {
            set_last_error("plugin not registered".into());
            return Vec::new();
        }
    };
    let req = LoadDemoRequest {
        grid_id,
        demo: demo.to_string(),
        ..Default::default()
    };
    match plugin.load_demo(req) {
        Ok(r) => {
            clear_last_error();
            let mut buf = Vec::new();
            let _ = r.encode(&mut buf);
            buf
        }
        Err(e) => {
            set_last_error(e);
            return Vec::new();
        }
    }
}

// =============================================================================
// WASM Stream Exports
// =============================================================================

#[wasm_bindgen]
pub fn volvox_grid_stream_open(method: &str) -> i64 {
    if get_volvox_grid_service_plugin().is_none() {
        set_last_error("plugin not registered".into());
        return -1;
    }

    let (method_id, mode) = match method {
        "/volvoxgrid.v1.VolvoxGridService/RenderSession" => (
            VolvoxGridServiceStreamMethod::RenderSession,
            VolvoxGridServiceStreamMode::Bidi,
        ),
        "/volvoxgrid.v1.VolvoxGridService/EventStream" => (
            VolvoxGridServiceStreamMethod::EventStream,
            VolvoxGridServiceStreamMode::Server,
        ),
        _ => {
            set_last_error(format!("unknown streaming method: {}", method));
            return -1;
        }
    };

    let handle = volvox_grid_service_next_stream_handle();
    STREAMS_VOLVOX_GRID_SERVICE.with(|streams| {
        streams
            .borrow_mut()
            .insert(handle, VolvoxGridServiceStreamContext::new(method_id, mode));
    });
    clear_last_error();
    handle
}

#[wasm_bindgen]
pub fn volvox_grid_stream_send(handle: i64, data: &[u8]) -> i32 {
    STREAMS_VOLVOX_GRID_SERVICE.with(|streams| {
        let mut streams = streams.borrow_mut();
        let ctx = match streams.get_mut(&handle) {
            Some(c) => c,
            None => {
                set_last_error(format!("invalid stream handle: {}", handle));
                return -1;
            }
        };

        if ctx.closed {
            set_last_error("stream is closed".into());
            return -1;
        }
        if ctx.send_closed {
            set_last_error("send side already closed".into());
            return -1;
        }
        if ctx.stream_error || ctx.finished {
            set_last_error("stream already finished".into());
            return -1;
        }

        if matches!(ctx.mode, VolvoxGridServiceStreamMode::Server)
            && (ctx.started || !ctx.send_queue.is_empty())
        {
            set_last_error("server stream accepts a single request".into());
            return -1;
        }

        ctx.send_queue.push_back(data.to_vec());

        if matches!(ctx.mode, VolvoxGridServiceStreamMode::Server) {
            volvox_grid_service_run_stream(ctx);
        }

        if ctx.stream_error {
            -1
        } else {
            clear_last_error();
            0
        }
    })
}

#[wasm_bindgen]
pub fn volvox_grid_stream_recv(handle: i64) -> Vec<u8> {
    STREAMS_VOLVOX_GRID_SERVICE.with(|streams| {
        let mut streams = streams.borrow_mut();
        let ctx = match streams.get_mut(&handle) {
            Some(c) => c,
            None => {
                set_last_error(format!("invalid stream handle: {}", handle));
                return stream_status(STREAM_STATUS_ERROR);
            }
        };

        if ctx.closed {
            set_last_error("stream is closed".into());
            return stream_status(STREAM_STATUS_ERROR);
        }

        if let Some(payload) = ctx.recv_queue.pop_front() {
            clear_last_error();
            return stream_pack(STREAM_STATUS_DATA, payload.as_slice());
        }

        if ctx.stream_error {
            return stream_status(STREAM_STATUS_ERROR);
        }

        if ctx.finished {
            clear_last_error();
            return stream_status(STREAM_STATUS_EOF);
        }

        clear_last_error();
        stream_status(STREAM_STATUS_PENDING)
    })
}

#[wasm_bindgen]
pub fn volvox_grid_stream_close_send(handle: i64) {
    STREAMS_VOLVOX_GRID_SERVICE.with(|streams| {
        let mut streams = streams.borrow_mut();
        let ctx = match streams.get_mut(&handle) {
            Some(c) => c,
            None => {
                set_last_error(format!("invalid stream handle: {}", handle));
                return;
            }
        };

        if ctx.closed {
            set_last_error("stream is closed".into());
            return;
        }

        if ctx.send_closed {
            clear_last_error();
            return;
        }

        ctx.send_closed = true;

        match ctx.mode {
            VolvoxGridServiceStreamMode::Server => {
                if !ctx.started {
                    if ctx.send_queue.is_empty() {
                        set_last_error("server stream request not sent".into());
                        ctx.stream_error = true;
                        ctx.finished = true;
                        ctx.started = true;
                    } else {
                        volvox_grid_service_run_stream(ctx);
                    }
                }
            }
            VolvoxGridServiceStreamMode::Client | VolvoxGridServiceStreamMode::Bidi => {
                volvox_grid_service_run_stream(ctx);
            }
        }

        if !ctx.stream_error {
            clear_last_error();
        }
    });
}

#[wasm_bindgen]
pub fn volvox_grid_stream_close(handle: i64) {
    STREAMS_VOLVOX_GRID_SERVICE.with(|streams| {
        let mut streams = streams.borrow_mut();
        if let Some(ctx) = streams.get_mut(&handle) {
            ctx.closed = true;
        }
        streams.remove(&handle);
    });
    clear_last_error();
}

// =============================================================================
// Error Retrieval
// =============================================================================

/// Returns the last error message, or an empty string if no error has occurred.
/// The error is cleared after each successful FFI call.
#[wasm_bindgen]
pub fn volvox_grid_last_error() -> String {
    LAST_ERROR.with(|e| e.borrow().clone())
}

